package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class CSVFormatTest {

    @Test
    void testGetEscapeWhenEscapeIsNull() throws Exception {
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class,
                Character.class,
                Object.class,  // Changed from CSVFormat.Quote.class to Object.class
                Character.class,
                Character.class,
                boolean.class,
                boolean.class,
                String.class,
                String.class,
                String[].class,
                boolean.class
        );
        constructor.setAccessible(true);
        CSVFormat format = constructor.newInstance(
                ',',
                '"',
                null,
                null,
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                false
        );
        assertNull(format.getEscape());
    }

    @Test
    void testGetEscapeWhenEscapeIsSet() throws Exception {
        Character escapeChar = '\\';
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class,
                Character.class,
                Object.class,  // Changed from CSVFormat.Quote.class to Object.class
                Character.class,
                Character.class,
                boolean.class,
                boolean.class,
                String.class,
                String.class,
                String[].class,
                boolean.class
        );
        constructor.setAccessible(true);
        CSVFormat format = constructor.newInstance(
                ',',
                '"',
                null,
                null,
                escapeChar,
                false,
                true,
                "\r\n",
                null,
                null,
                false
        );
        assertEquals(escapeChar, format.getEscape());
    }
}
